public boolean endOther(String a, String b) {
    a = a.toLowerCase();
    b = b.toLowerCase();

    // Check if b is a suffix of a
    int index = a.length() - b.length();
    if (index < 0) {
        return false;
    }
    return a.substring(index).equals(b);
}
