public boolean xyzThere(String str) {
    int len = str.length();
    // case when string ends with xyz or period is not there
    if (str.substring(len - 3).equals("xyz")) {
        return true;
    }
    // check for condition
    for (int i = 2; i < len - 1; i++) {
        if (str.charAt(i-2) != '.' && str.substring(i, i + 3).equals("xyz")) {
            return true;
        }
    }
    return false;
}

